public class BinarySearch {

    // Iterative — O(log n) time, O(1) space
    public static int search(int[] arr, int target) {
        int low = 0, high = arr.length - 1;

        while (low <= high) {
            int mid = low + (high - low) / 2; // avoids integer overflow vs (low+high)/2

            if (arr[mid] == target) return mid;
            if (arr[mid] < target)  low  = mid + 1;  // search right half
            else                    high = mid - 1;  // search left half
        }
        return -1; // not found
    }

    // Find FIRST occurrence of target in array with duplicates
    public static int firstOccurrence(int[] arr, int target) {
        int low = 0, high = arr.length - 1, result = -1;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (arr[mid] == target) {
                result = mid;
                high = mid - 1; // keep searching left
            } else if (arr[mid] < target) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        return result;
    }

    public static void main(String[] args) {
        int[] arr = {1, 3, 5, 7, 9, 11, 13};
        System.out.println(search(arr, 7));   // 3
        System.out.println(search(arr, 6));   // -1

        int[] dups = {1, 2, 2, 2, 3, 4};
        System.out.println(firstOccurrence(dups, 2)); // 1
    }
}

public class LinearSearch {

    // Basic search — returns first index of target, or -1
    public static int search(int[] arr, int target) {
        for (int i = 0; i < arr.length; i++) {
            if (arr[i] == target) return i;
        }
        return -1;
    }

    // Find ALL occurrences
    public static List<Integer> searchAll(int[] arr, int target) {
        List<Integer> indices = new ArrayList<>();
        for (int i = 0; i < arr.length; i++) {
            if (arr[i] == target) indices.add(i);
        }
        return indices;
    }

    // Search in a 2D array
    public static int[] search2D(int[][] matrix, int target) {
        for (int i = 0; i < matrix.length; i++) {
            for (int j = 0; j < matrix[i].length; j++) {
                if (matrix[i][j] == target) return new int[]{i, j};
            }
        }
        return new int[]{-1, -1};
    }

    public static void main(String[] args) {
        int[] arr = {5, 3, 8, 1, 9, 2};
        System.out.println(search(arr, 8));       // 2
        System.out.println(search(arr, 7));       // -1
        System.out.println(searchAll(new int[]{1,2,1,3,1}, 1)); // [0, 2, 4]
    }
}
